/// Computes per-basic-block incoming state for the current MIR body.
fn compute_block_states<'tcx>(
    tcx: TyCtxt<'tcx>,
    current_def_id: DefId,
    body: &Body<'tcx>,
    base_context: ContextKind,
) -> Vec<Option<BlockState<'tcx>>> {
    let mut in_states = vec![None; body.basic_blocks.len()];
    let mut entry_state = BlockState::empty();
    if base_context == ContextKind::BottomHalfL1
        && body.arg_count >= 1
        && short_type_name(tcx, peel_refs(body.local_decls[Local::from_usize(1)].ty))
            == "DisabledLocalIrqGuard"
    {
        entry_state.irq_guard_locals.insert(Local::from_usize(1));
    }
    in_states[BasicBlock::from_usize(0).as_usize()] = Some(entry_state);

    let predecessors = body.basic_blocks.predecessors().clone();
    let mut queue = VecDeque::from([BasicBlock::from_usize(0)]);

    while let Some(block) = queue.pop_front() {
        let mut state = in_states[block.as_usize()]
            .clone()
            .unwrap_or_else(BlockState::empty);

        let block_data = &body[block];
        for statement in &block_data.statements {
            apply_statement(tcx, body, &mut state, statement.kind.as_assign());
            if let StatementKind::StorageDead(local) = statement.kind {
                release_local(&mut state, local, statement.kind.name());
            }
        }

        if let Some(terminator) = &block_data.terminator {
            if let Some(effect) = classify_call_effect(
                tcx,
                current_def_id,
                body,
                &state,
                terminator.kind.as_call(),
            )
            {
                apply_effect(&mut state, &effect);
            } else if let TerminatorKind::Drop { place, .. } = &terminator.kind
                && let Some(local) = place.as_local()
            {
                release_local(&mut state, local, "Drop");
            }

            for successor in terminator.successors() {
                let joined = if let Some(existing) = &in_states[successor.as_usize()] {
                    join_states(existing, &state)
                } else if predecessors[successor].len() <= 1 {
                    state.clone()
                } else {
                    let pred_states = predecessors[successor]
                        .iter()
                        .filter_map(|predecessor| in_states[predecessor.as_usize()].as_ref().cloned())
                        .collect::<Vec<_>>();
                    join_many_states(&pred_states).unwrap_or_else(BlockState::empty)
                };

                if in_states[successor.as_usize()].as_ref() != Some(&joined) {
                    in_states[successor.as_usize()] = Some(joined);
                    queue.push_back(successor);
                }
            }
        }
    }

    in_states
}

/// Updates local alias information from one assignment statement.
fn apply_statement<'tcx>(
    tcx: TyCtxt<'tcx>,
    body: &Body<'tcx>,
    state: &mut BlockState<'tcx>,
    assign: Option<&(Place<'tcx>, rustc_middle::mir::Rvalue<'tcx>)>,
) {
    let Some((place, rvalue)) = assign else {
        return;
    };
    let Some(local) = place.as_local() else {
        return;
    };

    state.aliases.remove(&local);
    state.guards.remove(&local);
    state.irq_guard_locals.remove(&local);

    match rvalue {
        rustc_middle::mir::Rvalue::Ref(_, _, source) => {
            state.aliases.insert(local, resolve_alias(state, *source));
        }
        rustc_middle::mir::Rvalue::Use(operand) => {
            if let Some(source) = operand.place() {
                let source = resolve_alias(state, source);
                if source.as_local().is_some() {
                    state.aliases.insert(local, source);
                }
            }
        }
        rustc_middle::mir::Rvalue::Cast(_, operand, _) => {
            if let Some(source) = operand.place() {
                let source = resolve_alias(state, source);
                if source.as_local().is_some() {
                    state.aliases.insert(local, source);
                }
            }
        }
        _ => {
            let _ = tcx;
            let _ = body;
        }
    }
}

/// Classifies a MIR call terminator into one of the lockdep-relevant effects.
fn classify_call_effect<'tcx>(
    tcx: TyCtxt<'tcx>,
    current_def_id: DefId,
    body: &Body<'tcx>,
    state: &BlockState<'tcx>,
    call: Option<&rustc_middle::mir::TerminatorKind<'tcx>>,
) -> Option<CallEffect<'tcx>> {
    let rustc_middle::mir::TerminatorKind::Call {
        func,
        args,
        destination,
        ..
    } = call?
    else {
        return None;
    };

    let (def_id, _) = func.const_fn_def()?;
    let item_name = tcx.item_name(def_id);
    let method_name = item_name.as_str();
    let callee_path = tcx.def_path_str(def_id);

    if method_name == "drop" {
        let local = args.first()?.node.place()?.as_local()?;
        return Some(CallEffect::Release { local });
    }

    let receiver = resolve_alias(state, args.first()?.node.place()?);
    let destination = destination.as_local()?;
    let receiver_ty = peel_refs(args.first()?.node.ty(body, tcx));

    if method_name == "disable_irq" || method_name == "deref" {
        trace_lock_call(method_name, &callee_path, receiver_ty, true);
        return Some(CallEffect::Alias {
            destination,
            source: receiver,
        });
    }

    let lock = classify_lock_call(tcx, current_def_id, body, receiver, receiver_ty, method_name);
    trace_lock_call(method_name, &callee_path, receiver_ty, lock.is_some());
    let lock = lock?;
    if matches!(lock.acquire.as_str(), "try_lock" | "try_read" | "try_write") {
        return None;
    }

    Some(CallEffect::Acquire { destination, lock })
}

/// Traces candidate lock calls when `LOCKDEP_TRACE_CALLS` is enabled.
fn trace_lock_call(method_name: &str, callee_path: &str, receiver_ty: Ty<'_>, matched: bool) {
    if env::var_os("LOCKDEP_TRACE_CALLS").is_none() {
        return;
    }
    if matches!(
        method_name,
        "lock" | "read" | "write" | "try_lock" | "try_read" | "try_write" | "disable_irq"
    ) {
        eprintln!(
            "lockdep trace: method={method_name} matched={matched} callee={callee_path} receiver_ty={receiver_ty}",
        );
    }
}

/// Classifies one lock acquire call into a normalized lock artifact.
fn classify_lock_call<'tcx>(
    tcx: TyCtxt<'tcx>,
    current_def_id: DefId,
    body: &Body<'tcx>,
    receiver: Place<'tcx>,
    receiver_ty: Ty<'tcx>,
    method_name: &str,
) -> Option<LockInfoArtifact> {
    let lock_ty = peel_refs(receiver_ty);
    let ty::Adt(adt, args) = lock_ty.kind() else {
        return None;
    };
    let primitive = tcx.item_name(adt.did()).to_string();

    let acquire = match (&*primitive, method_name) {
        ("SpinLock", "lock" | "try_lock")
        | ("RwLock", "read" | "write" | "try_read" | "try_write")
        | ("Mutex", "lock" | "try_lock")
        | ("RwMutex", "read" | "write" | "try_read" | "try_write") => method_name.to_string(),
        _ => return None,
    };

    let guard_behavior = guard_behavior_for_call(tcx, *adt, args, method_name);
    Some(LockInfoArtifact {
        class: lock_class_key(tcx, current_def_id, body, receiver),
        primitive,
        acquire,
        guard_behavior,
    })
}

/// Determines the guard behavior associated with one recognized lock acquire.
fn guard_behavior_for_call<'tcx>(
    tcx: TyCtxt<'tcx>,
    adt: AdtDef<'tcx>,
    args: GenericArgsRef<'tcx>,
    method_name: &str,
) -> String {
    let item_name = tcx.item_name(adt.did());
    let primitive = item_name.as_str();
    if primitive == "Mutex" || primitive == "RwMutex" {
        return "Sleeping".into();
    }

    let guardian = args
        .types()
        .nth(1)
        .map(|ty| short_type_name(tcx, peel_refs(ty)))
        .unwrap_or_else(|| "Unknown".into());

    if primitive == "RwLock" && guardian == "WriteIrqDisabled" && method_name == "read" {
        "PreemptDisabled".into()
    } else {
        guardian
    }
}

/// Applies one abstract call effect to the current block state.
fn apply_effect<'tcx>(state: &mut BlockState<'tcx>, effect: &CallEffect<'tcx>) {
    match effect {
        CallEffect::Alias {
            destination,
            source,
        } => {
            state.aliases.insert(*destination, resolve_alias(state, *source));
            state.guards.remove(destination);
        }
        CallEffect::Acquire { destination, lock } => {
            state.guards.insert(*destination, lock.clone());
            state.aliases.remove(destination);
        }
        CallEffect::Release { local } => {
            state.guards.remove(local);
            state.aliases.remove(local);
            state.irq_guard_locals.remove(local);
        }
    }
}

/// Emits lock events and lock edges for one abstract call effect.
fn emit_effect(
    events: &mut Vec<LockEventArtifact>,
    edges: &mut Vec<LockEdgeArtifact>,
    entry_locks: &mut BTreeSet<LockInfoArtifact>,
    body: &Body<'_>,
    state: &BlockState<'_>,
    base_context: ContextKind,
    effect: CallEffect<'_>,
    location: Option<SourceLocation>,
) {
    match effect {
        CallEffect::Alias { .. } => {}
        CallEffect::Acquire { destination, lock } => {
            let context = context_for_acquire(state, base_context, &lock)
                .as_str()
                .to_string();
            if state.guards.is_empty() {
                entry_locks.insert(lock.clone());
            }
            for held in state.guards.values() {
                if is_deadlock_relevant_lock_pair(held, &lock) {
                    edges.push(LockEdgeArtifact {
                        context: context.clone(),
                        from: held.clone(),
                        to: lock.clone(),
                        location: location.clone(),
                    });
                }
            }

            events.push(LockEventArtifact {
                kind: "acquire".into(),
                context,
                lock,
                guard_local: Some(format_local(body, destination)),
                location,
            });
        }
        CallEffect::Release { local } => {
            if let Some(lock) = state.guards.get(&local).cloned() {
                events.push(LockEventArtifact {
                    kind: "release".into(),
                    context: current_context(state, base_context).as_str().to_string(),
                    lock,
                    guard_local: Some(format_local(body, local)),
                    location,
                });
            }
        }
    }
}

/// Collects one direct local call site for later summary propagation.
fn collect_callsite<'tcx>(
    tcx: TyCtxt<'tcx>,
    state: &BlockState<'tcx>,
    base_context: ContextKind,
    call: Option<&rustc_middle::mir::TerminatorKind<'tcx>>,
    location: Option<SourceLocation>,
) -> Option<CallSite> {
    let rustc_middle::mir::TerminatorKind::Call { func, .. } = call? else {
        return None;
    };
    let (callee, _) = func.const_fn_def()?;
    if !callee.is_local() || !tcx.def_kind(callee).is_fn_like() {
        return None;
    }

    Some(CallSite {
        callee,
        held_locks: state.guards.values().cloned().collect(),
        context: current_context(state, base_context),
        location,
    })
}

/// Computes a minimal “entry lock” summary for each local function.
fn compute_summary_entry_locks(
    analyses: &[FunctionAnalysis],
) -> HashMap<DefId, BTreeSet<LockInfoArtifact>> {
    let mut summaries = analyses
        .iter()
        .map(|analysis| (analysis.def_id, analysis.entry_locks.clone()))
        .collect::<HashMap<_, _>>();

    let mut changed = true;
    while changed {
        changed = false;
        for analysis in analyses {
            let mut merged = summaries
                .get(&analysis.def_id)
                .cloned()
                .unwrap_or_default();
            for callsite in analysis.callsites.iter().filter(|callsite| callsite.held_locks.is_empty())
            {
                if let Some(callee_locks) = summaries.get(&callsite.callee) {
                    let previous_len = merged.len();
                    merged.extend(callee_locks.iter().cloned());
                    changed |= merged.len() != previous_len;
                }
            }
            summaries.insert(analysis.def_id, merged);
        }
    }

    summaries
}

/// Finalizes one function analysis after interprocedural summary propagation.
fn finalize_function_analysis(
    mut analysis: FunctionAnalysis,
    summary_entry_locks: &HashMap<DefId, BTreeSet<LockInfoArtifact>>,
) -> FunctionArtifact {
    for callsite in &analysis.callsites {
        let Some(callee_locks) = summary_entry_locks.get(&callsite.callee) else {
            continue;
        };
        for held in &callsite.held_locks {
            for callee_lock in callee_locks {
                if is_deadlock_relevant_lock_pair(held, callee_lock) {
                    analysis.lock_edges.push(LockEdgeArtifact {
                        context: callsite.context.as_str().to_string(),
                        from: held.clone(),
                        to: callee_lock.clone(),
                        location: callsite.location.clone(),
                    });
                }
            }
        }
    }
    normalize_symmetric_ordered_edges(&mut analysis.lock_edges);
    dedup_edges(&mut analysis.lock_edges);

    FunctionArtifact {
        def_path: analysis.def_path,
        location: analysis.location,
        contexts: analysis
            .contexts
            .iter()
            .map(|context| context.as_str().to_string())
            .collect(),
        lock_events: analysis.lock_events,
        lock_edges: analysis.lock_edges,
    }
}

/// Normalizes symmetric reverse edges produced by one ordered double-lock helper.
fn normalize_symmetric_ordered_edges(edges: &mut Vec<LockEdgeArtifact>) {
    let mut keep = vec![true; edges.len()];

    for left_index in 0..edges.len() {
        if !keep[left_index] {
            continue;
        }
        for right_index in (left_index + 1)..edges.len() {
            if !keep[right_index] {
                continue;
            }

            let left = &edges[left_index];
            let right = &edges[right_index];

            let is_reverse_pair = left.context == right.context
                && left.from.primitive == right.from.primitive
                && left.to.primitive == right.to.primitive
                && left.from.acquire == right.from.acquire
                && left.to.acquire == right.to.acquire
                && left.from.class == right.to.class
                && left.to.class == right.from.class;

