/// Collects one direct local call site for later summary propagation.
fn collect_callsite<'tcx>(
    tcx: TyCtxt<'tcx>,
    state: &BlockState<'tcx>,
    base_context: ContextKind,
    call: Option<&rustc_middle::mir::TerminatorKind<'tcx>>,
    location: Option<SourceLocation>,
) -> Option<CallSite> {
    let rustc_middle::mir::TerminatorKind::Call { func, .. } = call? else {
        return None;
    };
    let (callee, _) = func.const_fn_def()?;
    if !callee.is_local() || !tcx.def_kind(callee).is_fn_like() {
        return None;
    }

    Some(CallSite {
        callee,
        held_locks: state.guards.values().cloned().collect(),
        context: current_context(state, base_context),
        location,
    })
}

/// Computes a minimal “entry lock” summary for each local function.
fn compute_summary_entry_locks(
    analyses: &[FunctionAnalysis],
) -> HashMap<DefId, BTreeSet<LockInfoArtifact>> {
    let mut summaries = analyses
        .iter()
        .map(|analysis| (analysis.def_id, analysis.entry_locks.clone()))
        .collect::<HashMap<_, _>>();

    let mut changed = true;
    while changed {
        changed = false;
        for analysis in analyses {
            let mut merged = summaries
                .get(&analysis.def_id)
                .cloned()
                .unwrap_or_default();
            for callsite in analysis.callsites.iter().filter(|callsite| callsite.held_locks.is_empty())
            {
                if let Some(callee_locks) = summaries.get(&callsite.callee) {
                    let previous_len = merged.len();
                    merged.extend(callee_locks.iter().cloned());
                    changed |= merged.len() != previous_len;
                }
            }
            summaries.insert(analysis.def_id, merged);
        }
    }

    summaries
}

/// Finalizes one function analysis after interprocedural summary propagation.
fn finalize_function_analysis(
    mut analysis: FunctionAnalysis,
    summary_entry_locks: &HashMap<DefId, BTreeSet<LockInfoArtifact>>,
) -> FunctionArtifact {
    for callsite in &analysis.callsites {
        let Some(callee_locks) = summary_entry_locks.get(&callsite.callee) else {
            continue;
        };
        for held in &callsite.held_locks {
            for callee_lock in callee_locks {
                if is_deadlock_relevant_lock_pair(held, callee_lock) {
                    analysis.lock_edges.push(LockEdgeArtifact {
                        context: callsite.context.as_str().to_string(),
                        from: held.clone(),
                        to: callee_lock.clone(),
                        location: callsite.location.clone(),
                    });
                }
            }
        }
    }
    normalize_symmetric_ordered_edges(&mut analysis.lock_edges);
    dedup_edges(&mut analysis.lock_edges);

    FunctionArtifact {
        def_path: analysis.def_path,
        location: analysis.location,
        contexts: analysis
            .contexts
            .iter()
            .map(|context| context.as_str().to_string())
            .collect(),
        lock_events: analysis.lock_events,
        lock_edges: analysis.lock_edges,
    }
}

/// Normalizes symmetric reverse edges produced by one ordered double-lock helper.
fn normalize_symmetric_ordered_edges(edges: &mut Vec<LockEdgeArtifact>) {
    let mut keep = vec![true; edges.len()];

    for left_index in 0..edges.len() {
        if !keep[left_index] {
            continue;
        }
        for right_index in (left_index + 1)..edges.len() {
            if !keep[right_index] {
                continue;
            }

            let left = &edges[left_index];
            let right = &edges[right_index];

            let is_reverse_pair = left.context == right.context
                && left.from.primitive == right.from.primitive
                && left.to.primitive == right.to.primitive
                && left.from.acquire == right.from.acquire
                && left.to.acquire == right.to.acquire
                && left.from.class == right.to.class
                && left.to.class == right.from.class;

            if !is_reverse_pair {
                continue;
            }

            let keep_left = canonical_edge_order(&left.from, &left.to);
            if keep_left {
                keep[right_index] = false;
            } else {
                keep[left_index] = false;
                break;
            }
        }
    }

    let mut index = 0usize;
    edges.retain(|_| {
        let decision = keep[index];
        index += 1;
        decision
    });
}

fn canonical_edge_order(from: &LockInfoArtifact, to: &LockInfoArtifact) -> bool {
    (from.class.as_str(), from.primitive.as_str(), from.acquire.as_str())
        <= (to.class.as_str(), to.primitive.as_str(), to.acquire.as_str())
}

fn is_deadlock_relevant_lock_pair(from: &LockInfoArtifact, to: &LockInfoArtifact) -> bool {
    !(is_shared_read_lock(from) && is_shared_read_lock(to))
}

fn is_shared_read_lock(lock: &LockInfoArtifact) -> bool {
    lock.acquire == "read" && matches!(lock.primitive.as_str(), "RwLock" | "RwMutex")
}

fn join_many_states<'tcx>(states: &[BlockState<'tcx>]) -> Option<BlockState<'tcx>> {
    let first = states.first()?.clone();
    Some(
        states[1..]
            .iter()
            .fold(first, |joined, state| join_states(&joined, state)),
    )
}

fn join_states<'tcx>(left: &BlockState<'tcx>, right: &BlockState<'tcx>) -> BlockState<'tcx> {
    let aliases = left
        .aliases
        .iter()
        .filter_map(|(local, place)| {
            right
                .aliases
                .get(local)
                .filter(|other| *other == place)
                .map(|_| (*local, *place))
        })
        .collect();
    let guards = left
        .guards
        .iter()
        .filter_map(|(local, lock)| {
            right
                .guards
                .get(local)
                .filter(|other| *other == lock)
                .map(|_| (*local, lock.clone()))
        })
        .collect();
    let irq_guard_locals = left
        .irq_guard_locals
        .intersection(&right.irq_guard_locals)
        .copied()
        .collect();

    BlockState {
        aliases,
        guards,
        irq_guard_locals,
    }
}

fn release_local<'tcx>(state: &mut BlockState<'tcx>, local: Local, _reason: &str) {
    state.guards.remove(&local);
    state.aliases.remove(&local);
    state.irq_guard_locals.remove(&local);
}

fn resolve_alias<'tcx>(state: &BlockState<'tcx>, place: Place<'tcx>) -> Place<'tcx> {
    let Some(local) = place.as_local() else {
        return place;
    };
    state.aliases.get(&local).copied().unwrap_or(place)
}

fn dedup_edges(edges: &mut Vec<LockEdgeArtifact>) {
    let mut seen = BTreeSet::new();
    edges.retain(|edge| {
        seen.insert((
            edge.from.class.clone(),
            edge.from.acquire.clone(),
            edge.to.class.clone(),
            edge.to.acquire.clone(),
            edge.location.as_ref().map(|location| {
                (location.file.clone(), location.line, location.column)
            }),
        ))
    });
}

fn peel_refs<'tcx>(mut ty: Ty<'tcx>) -> Ty<'tcx> {
    while let ty::Ref(_, inner, _) = ty.kind() {
        ty = *inner;
    }
    ty
}

fn short_type_name<'tcx>(tcx: TyCtxt<'tcx>, ty: Ty<'tcx>) -> String {
    match ty.kind() {
        ty::Adt(def, _) => tcx.item_name(def.did()).to_string(),
        _ => ty.to_string(),
    }
}

fn lock_class_key<'tcx>(
    tcx: TyCtxt<'tcx>,
    current_def_id: DefId,
    body: &Body<'tcx>,
    place: Place<'tcx>,
) -> String {
    let mut key = String::new();
    key.push_str(&place_root_key(tcx, current_def_id, body, place.local));

    for projection in place.projection.iter() {
        match projection {
            ProjectionElem::Deref => key.push_str(".*"),
            ProjectionElem::Field(field, _) => key.push_str(&format!(".field{}", field.index())),
            ProjectionElem::Downcast(_, variant) => {
                key.push_str(&format!(".variant{}", variant.as_usize()))
            }
            ProjectionElem::Index(local) => key.push_str(&format!("[idx:{}]", local.as_usize())),
            ProjectionElem::ConstantIndex {
                offset,
                min_length,
                from_end,
            } => key.push_str(&format!(
                "[const:{offset}:{min_length}:{}]",
                if from_end { "end" } else { "start" }
            )),
            ProjectionElem::Subslice { from, to, from_end } => key.push_str(&format!(
                "[subslice:{from}:{to}:{}]",
                if from_end { "end" } else { "start" }
            )),
            ProjectionElem::OpaqueCast(ty) | ProjectionElem::UnwrapUnsafeBinder(ty) => {
                key.push_str(&format!(".cast<{}>", short_type_name(tcx, peel_refs(ty))));
            }
        }
    }

    key
}

fn place_root_key<'tcx>(
    tcx: TyCtxt<'tcx>,
    current_def_id: DefId,
    body: &Body<'tcx>,
    local: Local,
) -> String {
    match local.as_usize() {
        0 => format!("{}::return", tcx.def_path_str(current_def_id)),
        index if index <= body.arg_count => format!("arg{index}"),
        index => format!("{}::local{index}", tcx.def_path_str(current_def_id)),
    }
}

fn span_to_location<'tcx>(tcx: TyCtxt<'tcx>, span: rustc_span::Span) -> Option<SourceLocation> {
    if span.is_dummy() {
        return None;
    }

    let source_map = tcx.sess.source_map();
    let location = source_map.lookup_char_pos(span.lo());
    Some(SourceLocation {
        file: location.file.name.prefer_local().to_string(),
        line: location.line,
        column: location.col_display + 1,
    })
}

fn current_context(state: &BlockState<'_>, base_context: ContextKind) -> ContextKind {
    let irq_disabled = !state.irq_guard_locals.is_empty()
        || state.guards.values().any(lock_disables_irq_while_held);
    match (base_context, irq_disabled) {
        (ContextKind::Task, true) => ContextKind::TaskIrqDisabled,
        (ContextKind::BottomHalfL1, true) => ContextKind::BottomHalfL1IrqDisabled,
        _ => base_context,
    }
}

fn context_for_acquire(
    state: &BlockState<'_>,
    base_context: ContextKind,
    lock: &LockInfoArtifact,
) -> ContextKind {
    if lock_disables_irq_while_held(lock) {
        match base_context {
            ContextKind::Task | ContextKind::TaskIrqDisabled => ContextKind::TaskIrqDisabled,
            ContextKind::BottomHalfL1 | ContextKind::BottomHalfL1IrqDisabled => {
                ContextKind::BottomHalfL1IrqDisabled
            }
            _ => base_context,
        }
    } else {
        current_context(state, base_context)
    }
}

fn lock_disables_irq_while_held(lock: &LockInfoArtifact) -> bool {
    lock.guard_behavior == "LocalIrqDisabled"
        || (lock.guard_behavior == "WriteIrqDisabled" && lock.acquire == "write")
}

impl ContextKind {
    fn as_str(self) -> &'static str {
        match self {
            ContextKind::Task => "Task",
            ContextKind::TaskIrqDisabled => "TaskIrqDisabled",
            ContextKind::HardIrqTopHalf => "HardIrqTopHalf",
            ContextKind::BottomHalfL1 => "BottomHalfL1",
            ContextKind::BottomHalfL1IrqDisabled => "BottomHalfL1IrqDisabled",
            ContextKind::BottomHalfL2 => "BottomHalfL2",
        }
    }
}

fn collect_entry_contexts<'tcx>(tcx: TyCtxt<'tcx>) -> HashMap<DefId, Vec<ContextKind>> {
    let mut map: HashMap<DefId, BTreeSet<ContextKind>> = HashMap::new();

    for local_def_id in tcx.mir_keys(()) {
        let def_id = local_def_id.to_def_id();
        if !tcx.def_kind(def_id).is_fn_like() {
            continue;
        }
        let body = tcx.optimized_mir(def_id);
        let callable_locals = collect_callable_locals(body);

        for block_data in body.basic_blocks.iter() {
            let Some(terminator) = &block_data.terminator else {
                continue;
            };
            let TerminatorKind::Call { func, args, .. } = &terminator.kind else {
                continue;
            };
            let Some((callee_def_id, _)) = func.const_fn_def() else {
                continue;
            };
            let callee_path = tcx.def_path_str(callee_def_id);
            let context = if callee_path.ends_with("register_bottom_half_handler_l1") {
                Some(ContextKind::BottomHalfL1)
            } else if callee_path.ends_with("register_bottom_half_handler_l2") {
                Some(ContextKind::BottomHalfL2)
            } else if tcx.item_name(callee_def_id).as_str() == "on_active" {
                Some(ContextKind::HardIrqTopHalf)
            } else {
                None
            };
            let Some(context) = context else {
                continue;
            };

            let callback_arg_index = if context == ContextKind::HardIrqTopHalf {
                1
            } else {
                0
            };
            let Some(callback) = args.get(callback_arg_index) else {
                continue;
            };
            if let Some(target_def_id) =
                resolve_callback_operand(callback.node.clone(), &callable_locals)
            {
                map.entry(target_def_id).or_default().insert(context);
            }
        }
    }

    map.into_iter()
        .map(|(def_id, contexts)| (def_id, contexts.into_iter().collect()))
        .collect()
}

fn collect_callable_locals<'tcx>(body: &Body<'tcx>) -> BTreeMap<Local, DefId> {
    let mut map = BTreeMap::new();

    for block_data in body.basic_blocks.iter() {
        for statement in &block_data.statements {
            let Some((place, rvalue)) = statement.kind.as_assign() else {
                continue;
            };
            let Some(local) = place.as_local() else {
                continue;
            };
            match rvalue {
                Rvalue::Aggregate(aggregate_kind, _) => match &**aggregate_kind {
                    AggregateKind::Closure(def_id, _)
                    | AggregateKind::CoroutineClosure(def_id, _) => {
                        map.insert(local, *def_id);
                    }
                    _ => {}
                },
                Rvalue::Use(operand) | Rvalue::Cast(_, operand, _) => {
                    if let Some((def_id, _)) = operand.const_fn_def() {
                        map.insert(local, def_id);
                    }
                }
                _ => {}
            }
        }
    }

    map
}

fn resolve_callback_operand<'tcx>(
    operand: rustc_middle::mir::Operand<'tcx>,
    callable_locals: &BTreeMap<Local, DefId>,
) -> Option<DefId> {
    if let Some((def_id, _)) = operand.const_fn_def() {
        return Some(def_id);
    }

    let local = operand.place()?.as_local()?;
    callable_locals.get(&local).copied()
}

trait TerminatorKindExt<'tcx> {
    fn as_call(&self) -> Option<&rustc_middle::mir::TerminatorKind<'tcx>>;
}

impl<'tcx> TerminatorKindExt<'tcx> for TerminatorKind<'tcx> {
    fn as_call(&self) -> Option<&rustc_middle::mir::TerminatorKind<'tcx>> {
        matches!(self, TerminatorKind::Call { .. }).then_some(self)
    }
}

fn format_local<'tcx>(body: &Body<'tcx>, local: Local) -> String {
    if local.as_usize() == 0 {
        return "return".into();
    }
    if local.as_usize() <= body.arg_count {
        return format!("arg{}", local.as_usize());
    }
    format!("_{}", local.as_usize())
}

