// SPDX-License-Identifier: MPL-2.0

//! MIR-based fact collection for the lockdep prototype.
//!
//! This module is responsible for:
//!
//! - identifying lock acquire/release operations in MIR;
//! - building per-function lock events and edges;
//! - recovering a minimal direct-call summary;
//! - recognizing IRQ entry contexts and propagating them through direct calls.

use std::collections::{BTreeMap, BTreeSet, HashMap, HashSet, VecDeque};
use std::env;

use rustc_middle::{
    mir::{
        AggregateKind, BasicBlock, Body, Local, Operand, Place, ProjectionElem, Rvalue,
        StatementKind, TerminatorKind,
    },
    ty::{self, AdtDef, GenericArgsRef, Ty, TyCtxt},
};
use rustc_span::source_map::Spanned;
use rustc_span::def_id::{DefId, LOCAL_CRATE};

use crate::model::{
    AnalysisArtifact, FunctionArtifact, LocalOriginKey, LockClassKey, LockEdgeArtifact,
    LockEventArtifact, LockInfoArtifact, LockRootKey, ProjectionKey, SourceLocation,
};

#[derive(Clone, Debug, PartialEq, Eq)]
struct BlockState<'tcx> {
    aliases: BTreeMap<Local, Place<'tcx>>,
    guards: BTreeMap<Local, LockInfoArtifact>,
    irq_guard_locals: BTreeSet<Local>,
    local_origins: BTreeMap<Local, LocalOriginKey>,
}

impl<'tcx> BlockState<'tcx> {
    fn empty() -> Self {
        Self {
            aliases: BTreeMap::new(),
            guards: BTreeMap::new(),
            irq_guard_locals: BTreeSet::new(),
            local_origins: BTreeMap::new(),
        }
    }
}

#[derive(Clone, Debug)]
enum CallEffect<'tcx> {
    Alias { destination: Local, source: Place<'tcx> },
    Acquire {
        destination: Local,
        lock: LockInfoArtifact,
    },
    Release {
        local: Local,
    },
}

/// One direct call site recorded for summary propagation.
#[derive(Clone, Debug)]
struct CallSite {
    callee: DefId,
    arg_bindings: BTreeMap<usize, LockClassKey>,
    held_locks: Vec<LockInfoArtifact>,
    context: ContextKind,
    location: Option<SourceLocation>,
}

/// Intermediate result for analyzing one MIR body under one base context.
#[derive(Clone, Debug)]
struct BodyAnalysis {
    lock_events: Vec<LockEventArtifact>,
    lock_edges: Vec<LockEdgeArtifact>,
    entry_locks: BTreeSet<LockInfoArtifact>,
    callsites: Vec<CallSite>,
}

/// Aggregated per-function analysis state before final serialization.
#[derive(Clone, Debug)]
struct FunctionAnalysis {
    def_id: DefId,
    def_path: String,
    location: Option<SourceLocation>,
    contexts: Vec<ContextKind>,
    lock_events: Vec<LockEventArtifact>,
    lock_edges: Vec<LockEdgeArtifact>,
    entry_locks: BTreeSet<LockInfoArtifact>,
    callsites: Vec<CallSite>,
}

/// Execution contexts currently recognized by the prototype.
#[derive(Clone, Copy, Debug, PartialEq, Eq, PartialOrd, Ord)]
enum ContextKind {
    Task,
    TaskIrqDisabled,
    HardIrqTopHalf,
    BottomHalfL1,
    BottomHalfL1IrqDisabled,
    BottomHalfL2,
}

/// Collects the full crate artifact from MIR bodies in the current crate.
pub fn collect_artifact<'tcx>(tcx: TyCtxt<'tcx>) -> AnalysisArtifact {
    let crate_name = tcx.crate_name(LOCAL_CRATE).to_string();
    let package_name = env::var("CARGO_PKG_NAME").unwrap_or_else(|_| crate_name.clone());
    let manifest_dir = env::var("CARGO_MANIFEST_DIR").unwrap_or_default();
    let target = env::var("TARGET").ok();
    let is_primary_package = env::var("CARGO_PRIMARY_PACKAGE").is_ok();

    let entry_contexts = collect_entry_contexts(tcx);
    let direct_calls = collect_direct_calls(tcx);
    let propagated_contexts = propagate_contexts(&entry_contexts, &direct_calls);

    let analyses = tcx
        .mir_keys(())
        .iter()
        .filter(|local_def_id| tcx.def_kind(local_def_id.to_def_id()).is_fn_like())
        .map(|local_def_id| {
            let def_id = local_def_id.to_def_id();
            let body = tcx.optimized_mir(def_id);
            let location = span_to_location(tcx, tcx.def_span(def_id));
            let contexts = propagated_contexts
                .get(&def_id)
                .cloned()
                .unwrap_or_else(|| vec![ContextKind::Task]);

            let mut lock_events = Vec::new();
            let mut lock_edges = Vec::new();
            let mut entry_locks = BTreeSet::new();
            let mut callsites = Vec::new();
            for context in &contexts {
                let analysis = analyze_body(tcx, def_id, body, *context);
                lock_events.extend(analysis.lock_events);
                lock_edges.extend(analysis.lock_edges);
                entry_locks.extend(analysis.entry_locks);
                callsites.extend(analysis.callsites);
            }

            FunctionAnalysis {
                def_id,
                def_path: tcx.def_path_str(def_id),
                location,
                contexts,
                lock_events,
                lock_edges,
                entry_locks,
                callsites,
            }
        })
        .collect::<Vec<_>>();

    let summary_entry_locks = compute_summary_entry_locks(&analyses);

    let mut functions = analyses
        .into_iter()
        .map(|analysis| finalize_function_analysis(analysis, &summary_entry_locks))
        .collect::<Vec<_>>();
    functions.sort_by(|left, right| left.def_path.cmp(&right.def_path));

    AnalysisArtifact {
        crate_name,
        package_name,
        manifest_dir,
        target,
        is_primary_package,
        functions,
    }
}

/// Collects direct crate-local call edges for context propagation.
fn collect_direct_calls<'tcx>(tcx: TyCtxt<'tcx>) -> HashMap<DefId, HashSet<DefId>> {
    let mut graph = HashMap::<DefId, HashSet<DefId>>::new();

    for local_def_id in tcx.mir_keys(()) {
        let caller = local_def_id.to_def_id();
        if !tcx.def_kind(caller).is_fn_like() {
            continue;
        }

        let body = tcx.optimized_mir(caller);
        let mut callees = HashSet::new();
        for block_data in body.basic_blocks.iter() {
            let Some(terminator) = &block_data.terminator else {
                continue;
            };
            let TerminatorKind::Call { func, .. } = &terminator.kind else {
                continue;
            };
            let Some((callee, _)) = func.const_fn_def() else {
                continue;
            };
            if callee.is_local() && tcx.def_kind(callee).is_fn_like() {
                callees.insert(callee);
            }
        }
        graph.insert(caller, callees);
    }

    graph
}

