/// Collects the full crate artifact from MIR bodies in the current crate.
pub fn collect_artifact<'tcx>(tcx: TyCtxt<'tcx>) -> AnalysisArtifact {
    let crate_name = tcx.crate_name(LOCAL_CRATE).to_string();
    let package_name = env::var("CARGO_PKG_NAME").unwrap_or_else(|_| crate_name.clone());
    let manifest_dir = env::var("CARGO_MANIFEST_DIR").unwrap_or_default();
    let target = env::var("TARGET").ok();
    let is_primary_package = env::var("CARGO_PRIMARY_PACKAGE").is_ok();

    let entry_contexts = collect_entry_contexts(tcx);
    let direct_calls = collect_direct_calls(tcx);
    let propagated_contexts = propagate_contexts(&entry_contexts, &direct_calls);

    let analyses = tcx
        .mir_keys(())
        .iter()
        .filter(|local_def_id| tcx.def_kind(local_def_id.to_def_id()).is_fn_like())
        .map(|local_def_id| {
            let def_id = local_def_id.to_def_id();
            let body = tcx.optimized_mir(def_id);
            let location = span_to_location(tcx, tcx.def_span(def_id));
            let contexts = propagated_contexts
                .get(&def_id)
                .cloned()
                .unwrap_or_else(|| vec![ContextKind::Task]);

            let mut lock_events = Vec::new();
            let mut lock_edges = Vec::new();
            let mut lock_usage_states = Vec::new();
            let mut entry_locks = BTreeSet::new();
            let mut callsites = Vec::new();
            for context in &contexts {
                let analysis = analyze_body(tcx, def_id, body, *context);
                lock_events.extend(analysis.lock_events);
                lock_edges.extend(analysis.lock_edges);
                lock_usage_states.extend(analysis.lock_usage_states);
                entry_locks.extend(analysis.entry_locks);
                callsites.extend(analysis.callsites);
            }

            FunctionAnalysis {
                def_id,
                def_path: tcx.def_path_str(def_id),
                location,
                contexts,
                lock_events,
                lock_edges,
                lock_usage_states,
                entry_locks,
                callsites,
            }
        })
        .collect::<Vec<_>>();

    let summary_entry_locks = compute_summary_entry_locks(&analyses);

    let mut functions = analyses
        .into_iter()
        .map(|analysis| finalize_function_analysis(analysis, &summary_entry_locks))
        .collect::<Vec<_>>();
    functions.sort_by(|left, right| left.def_path.cmp(&right.def_path));

    AnalysisArtifact {
        crate_name,
        package_name,
        manifest_dir,
        target,
        is_primary_package,
        functions,
    }
}

/// Collects direct crate-local call edges for context propagation.
fn collect_direct_calls<'tcx>(tcx: TyCtxt<'tcx>) -> HashMap<DefId, HashSet<DefId>> {
    let mut graph = HashMap::<DefId, HashSet<DefId>>::new();

    for local_def_id in tcx.mir_keys(()) {
        let caller = local_def_id.to_def_id();
        if !tcx.def_kind(caller).is_fn_like() {
            continue;
        }

        let body = tcx.optimized_mir(caller);
        let mut callees = HashSet::new();
        for block_data in body.basic_blocks.iter() {
            let Some(terminator) = &block_data.terminator else {
                continue;
            };
            let TerminatorKind::Call { func, .. } = &terminator.kind else {
                continue;
            };
            let Some((callee, _)) = func.const_fn_def() else {
                continue;
            };
            if callee.is_local() && tcx.def_kind(callee).is_fn_like() {
                callees.insert(callee);
            }
        }
        graph.insert(caller, callees);
    }

    graph
}

/// Propagates non-task IRQ entry contexts through direct local calls.
fn propagate_contexts(
    entry_contexts: &HashMap<DefId, Vec<ContextKind>>,
    direct_calls: &HashMap<DefId, HashSet<DefId>>,
) -> HashMap<DefId, Vec<ContextKind>> {
    let mut propagated = entry_contexts
        .iter()
        .map(|(def_id, contexts)| (*def_id, contexts.iter().copied().collect::<BTreeSet<_>>()))
        .collect::<HashMap<_, _>>();

    let mut queue = VecDeque::new();
    for (&def_id, contexts) in &propagated {
        for &context in contexts {
            queue.push_back((def_id, context));
        }
    }

    while let Some((caller, context)) = queue.pop_front() {
        let Some(callees) = direct_calls.get(&caller) else {
            continue;
        };
        for &callee in callees {
            let entry = propagated.entry(callee).or_default();
            if entry.insert(context) {
                queue.push_back((callee, context));
            }
        }
    }

    propagated
        .into_iter()
        .map(|(def_id, contexts)| {
            let mut contexts = contexts.into_iter().collect::<Vec<_>>();
            if contexts.is_empty() {
                contexts.push(ContextKind::Task);
            }
            (def_id, contexts)
        })
        .collect()
}

